package org.apache.commons.lang3;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import org.junit.jupiter.api.Test;

/**
 * Tests {@link BitField} constructed with int masks.
 */
class BitFieldTest extends AbstractLangTest {

    private static final BitField BF_MULTI = new BitField(0x3F80);

    private static final BitField BF_SINGLE = new BitField(0x4000);

    private static final BitField BF_ZERO = new BitField(0);

    @Test
    void testByteBoolean() {
        assertEquals(0, new BitFieldPrimitives(new BitField(0)).setByteBoolean((byte) 0, true));
        assertEquals(1, new BitFieldPrimitives(new BitField(1)).setByteBoolean((byte) 0, true));
        assertEquals(2, new BitFieldPrimitives(new BitField(2)).setByteBoolean((byte) 0, true));
        assertEquals(4, new BitFieldPrimitives(new BitField(4)).setByteBoolean((byte) 0, true));
        assertEquals(8, new BitFieldPrimitives(new BitField(8)).setByteBoolean((byte) 0, true));
        assertEquals(16, new BitFieldPrimitives(new BitField(16)).setByteBoolean((byte) 0, true));
        assertEquals(32, new BitFieldPrimitives(new BitField(32)).setByteBoolean((byte) 0, true));
        assertEquals(64, new BitFieldPrimitives(new BitField(64)).setByteBoolean((byte) 0, true));
        assertEquals(-128, new BitFieldPrimitives(new BitField(128)).setByteBoolean((byte) 0, true));
        assertEquals(1, new BitFieldPrimitives(new BitField(0)).setByteBoolean((byte) 1, false));
        assertEquals(0, new BitFieldPrimitives(new BitField(1)).setByteBoolean((byte) 1, false));
        assertEquals(0, new BitFieldPrimitives(new BitField(2)).setByteBoolean((byte) 2, false));
        assertEquals(0, new BitFieldPrimitives(new BitField(4)).setByteBoolean((byte) 4, false));
        assertEquals(0, new BitFieldPrimitives(new BitField(8)).setByteBoolean((byte) 8, false));
        assertEquals(0, new BitFieldPrimitives(new BitField(16)).setByteBoolean((byte) 16, false));
        assertEquals(0, new BitFieldPrimitives(new BitField(32)).setByteBoolean((byte) 32, false));
        assertEquals(0, new BitFieldPrimitives(new BitField(64)).setByteBoolean((byte) 64, false));
        assertEquals(0, new BitFieldPrimitives(new BitField(128)).setByteBoolean((byte) 128, false));
        assertEquals(-2, new BitFieldPrimitives(new BitField(1)).setByteBoolean((byte) 255, false));
        final byte clearedBit = new BitFieldPrimitives(new BitField(0x40)).setByteBoolean((byte) -63, false);
        assertFalse(new BitField(0x40).isSet(clearedBit));
    }

