    /**
     * test the setShortValue() method
     */
    @Test
    void testSetShortValue() {
        final int limit = 128;
        for (int j = 0; j < limit; j++) {
            assertEquals(new BitFieldPrimitives(BF_MULTI).getShortValue(new BitFieldPrimitives(BF_MULTI).setShortValue((short) 0, (short) j)), (short) j);
            assertEquals(new BitFieldPrimitives(BF_MULTI).setShortValue((short) 0, (short) j), (short) (j << 7));
        }
        for (int j = 0; j < limit; j++) {
            assertEquals(new BitFieldPrimitives(BF_ZERO).getShortValue(new BitFieldPrimitives(BF_ZERO).setShortValue((short) 0, (short) j)), (short) 0);
            assertEquals(new BitFieldPrimitives(BF_ZERO).setShortValue((short) 0, (short) j), (short) 0);
        }
        // verify that excess bits are stripped off
        assertEquals(new BitFieldPrimitives(BF_MULTI).setShortValue((short) 0x3f80, (short) 128), (short) 0);
        for (int j = 0; j < 2; j++) {
            assertEquals(new BitFieldPrimitives(BF_SINGLE).getShortValue(new BitFieldPrimitives(BF_SINGLE).setShortValue((short) 0, (short) j)), (short) j);
            assertEquals(new BitFieldPrimitives(BF_SINGLE).setShortValue((short) 0, (short) j), (short) (j << 14));
        }
        // verify that excess bits are stripped off
        assertEquals(new BitFieldPrimitives(BF_SINGLE).setShortValue((short) 0x4000, (short) 2), (short) 0);
    }

    /**
     * test the setValue() method
     */
    @Test
    void testSetValue() {
        final int limit = 128;
        for (int j = 0; j < limit; j++) {
            assertEquals(BF_MULTI.getValue(BF_MULTI.setValue(0, j)), j);
            assertEquals(BF_MULTI.setValue(0, j), j << 7);
        }
        for (int j = 0; j < limit; j++) {
            assertEquals(BF_ZERO.getValue(BF_ZERO.setValue(0, j)), 0);
            assertEquals(BF_ZERO.setValue(0, j), 0);
        }
        // verify that excess bits are stripped off
        assertEquals(BF_MULTI.setValue(0x3f80, 128), 0);
        for (int j = 0; j < 2; j++) {
            assertEquals(BF_SINGLE.getValue(BF_SINGLE.setValue(0, j)), j);
            assertEquals(BF_SINGLE.setValue(0, j), j << 14);
        }
        // verify that excess bits are stripped off
        assertEquals(BF_SINGLE.setValue(0x4000, 2), 0);
    }
